3963       match(FV, m_SExt(m_c_ICmp(ExtendedCmpPredicate, m_Specific(LHS),
3964                                 m_Specific(RHS)))) &&
3965       (ExtendedCmpPredicate == ICmpInst::ICMP_NE ||
3966        ICmpInst::getSwappedPredicate(ExtendedCmpPredicate) == Pred))
3967     Replace = true;
