3977       FalseBranchSelectPredicate =
3978           ICmpInst::getSwappedPredicate(FalseBranchSelectPredicate);
3979       std::swap(LHS, RHS);
3980     }
3981 
3982     if (!InnerTV->isOne()) {
3983       std::swap(InnerTV, InnerFV);
3984       std::swap(LHS, RHS);
3985     }
