 982   // (X != 0) && (ctpop(X) u< 2) --> ctpop(X) == 1
 983   Value *X;
 984   if (JoinedByAnd &&
 985       match(Cmp0, m_SpecificICmp(ICmpInst::ICMP_NE, m_Value(X), m_ZeroInt())) &&
 986       match(Cmp1, m_SpecificICmp(ICmpInst::ICMP_ULT,
 987                                  m_Intrinsic<Intrinsic::ctpop>(m_Specific(X)),
 988                                  m_SpecificInt(2)))) {
 989     auto *CtPop = cast<Instruction>(Cmp1->getOperand(0));
 990     // Drop range attributes and re-infer them in the next iteration.
 991     CtPop->dropPoisonGeneratingAnnotations();
 992     IC.addToWorklist(CtPop);
 993     return Builder.CreateICmpEQ(CtPop, ConstantInt::get(CtPop->getType(), 1));
 994   }
 995   // (X == 0) || (ctpop(X) u> 1) --> ctpop(X) != 1
 996   if (!JoinedByAnd &&
 997       match(Cmp0, m_SpecificICmp(ICmpInst::ICMP_EQ, m_Value(X), m_ZeroInt())) &&
 998       match(Cmp1, m_SpecificICmp(ICmpInst::ICMP_UGT,
