1000                                  m_SpecificInt(1)))) {
1001     auto *CtPop = cast<Instruction>(Cmp1->getOperand(0));
1002     // Drop range attributes and re-infer them in the next iteration.
1003     CtPop->dropPoisonGeneratingAnnotations();
